(function(){
  function Sigma(graph,container){this.graph=graph;this.container=container;this.handlers={};this.camera={x:0,y:0,ratio:1,animate:function(next){this.x=next.x||this.x;this.y=next.y||this.y;this.ratio=next.ratio||this.ratio;}};if(container){container.addEventListener('click',()=>{});} }
  Sigma.prototype.on=function(evt,handler){this.handlers[evt]=handler;};
  Sigma.prototype.refresh=function(){};
  Sigma.prototype.getCamera=function(){return this.camera;};
  window.Sigma=Sigma;
})();
